library(haven); library(dplyr); library(readr); dir.create("data/output", recursive = TRUE, showWarnings = FALSE); wave1 <- read_delim("data/input/wave_one_lsype_family_background_2020.tab", delim = "\t", show_col_types = FALSE); wave2 <- read_delim("data/input/wave_two_lsype_family_background_2020.tab", delim = "\t", show_col_types = FALSE); wave3 <- read_delim("data/input/wave_three_lsype_family_background_2020.tab", delim = "\t", show_col_types = FALSE); wave4 <- read_delim("data/input/wave_four_lsype_family_background_2020.tab", delim = "\t", show_col_types = FALSE); wave5 <- read_delim("data/input/wave_five_lsype_family_background_2020.tab", delim = "\t", show_col_types = FALSE); wave1_clean <- wave1 %>% select(NSID, W1nsseccatmum, W1nsseccatdad) %>% rename(nssecma14 = W1nsseccatmum, nssecpa14 = W1nsseccatdad); wave2_clean <- wave2 %>% select(NSID, W2nsseccatmum, W2nsseccatdad) %>% rename(nssecma15 = W2nsseccatmum, nssecpa15 = W2nsseccatdad); wave3_clean <- wave3 %>% select(NSID, W3cnsseccatmum, W3cnsseccatdad) %>% rename(nssecma16 = W3cnsseccatmum, nssecpa16 = W3cnsseccatdad); wave4_clean <- wave4 %>% select(NSID, w4cnsseccatmum, w4cnsseccatdad) %>% rename(nssecma17 = w4cnsseccatmum, nssecpa17 = w4cnsseccatdad); wave5_clean <- wave5 %>% select(NSID, w5Cnsseccatmum, w5Cnsseccatdad) %>% rename(nssecma18 = w5Cnsseccatmum, nssecpa18 = w5Cnsseccatdad); merged_data <- wave1_clean %>% full_join(wave2_clean, by = "NSID") %>% full_join(wave3_clean, by = "NSID") %>% full_join(wave4_clean, by = "NSID") %>% full_join(wave5_clean, by = "NSID"); harmonize_nssec <- function(x) { x <- as.numeric(x); int_x <- floor(x); result <- case_when(is.na(x) ~ -3, x == -999 ~ -2, x == -94 ~ -8, x %in% c(-99, -98) ~ -3, int_x >= 1 & int_x <= 17 ~ int_x, TRUE ~ -3); return(result) }; merged_data <- merged_data %>% mutate(nssecma14 = harmonize_nssec(nssecma14), nssecpa14 = harmonize_nssec(nssecpa14), nssecma15 = harmonize_nssec(nssecma15), nssecpa15 = harmonize_nssec(nssecpa15), nssecma16 = harmonize_nssec(nssecma16), nssecpa16 = harmonize_nssec(nssecpa16), nssecma17 = harmonize_nssec(nssecma17), nssecpa17 = harmonize_nssec(nssecpa17), nssecma18 = harmonize_nssec(nssecma18), nssecpa18 = harmonize_nssec(nssecpa18)); final_data <- merged_data %>% select(NSID, nssecma14, nssecpa14, nssecma15, nssecpa15, nssecma16, nssecpa16, nssecma17, nssecpa17, nssecma18, nssecpa18); write_csv(final_data, "data/output/cleaned_data.csv"); cat("Data cleaning complete. Rows:", nrow(final_data), "Cols:", ncol(final_data), "\n")